import face_recognition
from flask import Flask, request, jsonify
from PIL import Image
import numpy as np
import os
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import StandardScaler
from sklearn.ensemble import RandomForestClassifier
from sklearn.metrics import accuracy_score, classification_report, confusion_matrix

app = Flask(__name__)

# Load employee photos and extract face encodings
def load_employee_photos():
    employee_photos = []
    for file in os.listdir('employee_photos'):
        image = face_recognition.load_image_file(os.path.join('employee_photos', file))
        encoding = face_recognition.face_encodings(image)[0]
        employee_photos.append(encoding)
    return np.array(employee_photos)

# Train model on employee photos
def train_model():
    employee_photos = load_employee_photos()
    X_train, X_test, y_train, y_test = train_test_split(employee_photos, [1]*len(employee_photos), test_size=0.2, random_state=42)
    scaler = StandardScaler()
    X_train_scaled = scaler.fit_transform(X_train)
    model = RandomForestClassifier(n_estimators=100)
    model.fit(X_train_scaled, y_train)
    return model

# API endpoint to get confidence scores for all training classes
@app.route('/confidence_scores', methods=['POST'])
def get_confidence_scores():
    image = request.files['image']
    image_array = face_recognition.load_image_file(image)
    encoding = face_recognition.face_encodings(image_array)[0]
    model = train_model()
    predictions = model.predict_proba(np.array([encoding]))
    return jsonify({'confidence_scores': [p[1] for p in predictions]})

# API endpoint to get detailed probability distribution over all known faces
@app.route('/probability_distribution', methods=['POST'])
def get_probability_distribution():
    image = request.files['image']
    image_array = face_recognition.load_image_file(image)
    encoding = face_recognition.face_encodings(image_array)[0]
    model = train_model()
    predictions = model.predict_proba(np.array([encoding]))
    return jsonify({'probability_distribution': [p[1] for p in predictions]})

if __name__ == '__main__':
    app.run(debug=True)

